description:
Setting socketTimeoutMS or connectTimeoutMS to 0 when calling MongoClient.connect(url, options, callback) results in a timeout value of 120000.

This code in mongo_client.js does not correctly handle a setting of 0:

  // Check if we have connection and socket timeout set
  if(!_finalOptions.socketTimeoutMS) _finalOptions.socketTimeoutMS = 120000;
  if(!_finalOptions.connectTimeoutMS) _finalOptions.connectTimeoutMS = 120000;

We're having issues updating the driver from version 1.4.40 to 2.2.9.

The main issue is that all the queries are freezed or 10s every 30 seconds or so (it’s random). Please find the details bellow.

+Context+
* mongo cluster in version 2.6.11 ;
* node is in version 4.5.0 ;
* Please find attached a very simple code sample to reproduce.

+Old driver behaviour+
* 1 db connection is opened and never close ;
* 5 TCP connections are opened and never close ;
* Queries are running without any issue.

+New driver behaviour+
* 1 db connection is opened and never close ;
* At first only 5 TCP connections are opened but then the number of connections starts to increase progressively until it reaches 15 ;
* Looking at a tcpdump only one connection seems to be in use at a time ;
* Sometimes one of those TCP connections is closed (without going in TIME_WAIT state) and all queries are freezed for 10s ;

+Further testing+
* We've tested to decrease and increase the pool size. The result is the same but the number of tcp connections differs. For a pool size of 1, we've 3 TCP connections (with the old driver it opens only 1 tcp connection) at the same time and it's working fine. As soon as the 4th one gets created it freezes all the queries.
* We've tested to do only one query at a time, behaviour is the same but it get's frozen faster.

Thanks for your help!

*Test - 100 parallel findOne query*
*Result - each query time increase*

If TIME DISPERSION is higher than 1000 ms each query time is between 20ms - 200ms.

The same results for replicaSet/host setup with different poolSize values.

{code:JavaScript|borderStyle=solid}
var mongo = require('mongodb');
var async = require('async');
var MongoClient = mongo.MongoClient;
var db;

const URL = "mongodb://USER:PASS@SERVER1:27017,SERVER2:27017/DB_NAME?replicaSet=REPLICA_SET";
const OPTIONS = {
    "db": {
        "readPreference": "nearest",
        "poolSize": 10
    },
    "server": {
        "poolSize": 10
    },
    "replSet": {
        "replicaSet": "REPLICA_SET",
        "poolSize": 10
    }
};

MongoClient.connect(URL, OPTIONS, function (err, result) {
    if (err) {
        console.error(err.message);
    } else {
        db = result;
        console.log("Connected to server");
        db.collection('TEST_COLLECTION', function (err, result) {
            db.TEST_COLLECTION = result;
            startTest();
        });
    }
});


function startTest() {
    var queue = [];
    for (var i = 1; i <= 100; i++) {
        queue.push(runQuery);
    }

    var startTime = new Date().getTime();
    async.parallel(queue, function () {
        var endTime = new Date().getTime();
        console.log("TOTAL TIME : " + (endTime - startTime));
    });
}

const QUERY = {"_id": "436b3e335b71c99202d621345a71f0c6"};
const TIME_DISPERSION = 10; //ms - OK with values >= 1000ms

function runQuery(cb) {
    setTimeout(function () {
        var startTime = new Date().getTime();
        db.TEST_COLLECTION.findOne(QUERY, function (err, result) {
            var endTime = new Date().getTime();
            console.log("Time: " + (endTime - startTime));
            cb();
        });
    }, parseInt(Math.random() * TIME_DISPERSION));
}
